#include <bits/stdc++.h>
using namespace std;
const int maxn=4e3+5;
int a[maxn][maxn],dp[maxn][maxn],ans=INT_MIN,q[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	memset(dp,-0x3f,sizeof(dp));
	int n,m,k,T;
	cin>>n>>m>>k>>T;
	if(n==0) {
		cout<<0;
		return 0;
	}

	int h=1,t=0;
	for(int i=1,x,y,z; i<=k; i++) {
		cin>>x>>y>>z;
		a[x][y]=z;
	}
	for(int i=1; i<=m; i++) {
		dp[1][i]=a[1][i];
	}
	q[h]=1;
	for(int i=2; i<=n; i++) {
		int h=1,t=0,p=1;
		for(int j=1; j<=m; j++) {
			int r=min(m,j+T);
			while(p<=r) {
				while(h<=t&&dp[i-1][q[t]]<=dp[i-1][p]) {
					t--;
				}
				q[++t]=p;
				p++;
			}
			while(h<t&&q[h]<j-T) {
				h++;
			}
			if(h<=t&&dp[i-1][q[h]]>=-1e9) {
				dp[i][j]=dp[i-1][q[h]]+a[i][j];
			}
		}
	}
	for(int i=1; i<=m; i++) {
		ans=max(dp[n][i],ans);
	}
	cout<<ans;
	return 0;
}
